public class ModScreenHandlers {
    public static final ScreenHandlerType<TradingScreenHandler> TRADING = new ScreenHandlerType<>(TradingScreenHandler::new);
    public static void register() {
        Registry.register(Registries.SCREEN_HANDLER, new Identifier("modid", "trading"), TRADING);
    }
}

public class TradingScreen extends HandledScreen<TradingScreenHandler> {
    private static final Identifier TEXTURE = new Identifier("modid", "textures/gui/trading.png");
    public TradingScreen(TradingScreenHandler handler, PlayerInventory inventory, Text title) {
        super(handler, inventory, title);
    }
    @Override
    protected void drawBackground(DrawContext context, float delta, int mouseX, int mouseY) {
        int x = (width - backgroundWidth) / 2;
        int y = (height - backgroundHeight) / 2;
        context.drawTexture(TEXTURE, x, y, 0, 0, backgroundWidth, backgroundHeight);
    }
}
